import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/macos-downloads.DCRwPSpe.js";const o=JSON.parse(`{"title":"Установка Fabric","description":"Пошаговая инструкция по установке Fabric.","frontmatter":{"title":"Установка Fabric","description":"Пошаговая инструкция по установке Fabric.","authors":["Benonardo","IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"ru_ru/1.21.8/players/installing-fabric.md","filePath":"versions/1.21.8/translated/ru_ru/players/installing-fabric.md","lastUpdated":1760721669000}`);var s={name:`ru_ru/1.21.8/players/installing-fabric.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Fabric”">​</a></h1><p>Это руководство применимо только к официальному лаунчеру Minecraft. Для сторонних лаунчеров вам следует ознакомиться с их документацией.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузка установщика Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузка установщика Fabric”">​</a></h2><p>Вы можете загрузить установщик Fabric с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сайта Fabric</a>.</p><p>Если вы используете Windows, скачайте версию <code>.exe</code> (<code>Download For Windows</code>), потому что для неё не требуется Java в вашей системе. Вместо этого он использует версию Java из официального лаунчера.</p><p>Для macOS и Linux вам потребуется установить версию <code>.jar</code>. Иногда вам необходимо установить Java перед выполнением этого шага.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запуск установщика Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запуск установщика Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Прежде чем запускать установщик, закройте Minecraft и Minecraft лаунчер.</p></div><details class="details custom-block"><summary>Информация для пользователей macOS</summary><p>На macOS вам может потребоваться щелкнуть правой кнопкой мыши на файл <code>.jar</code> и нажать <code>Открыть</code>, чтобы запустить его.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Контекстное меню установщика Fabric на MacOS" loading="lazy"></p><p>Когда вас спросят: &quot;Вы уверены, что хотите это открыть?&quot;, нажмите <code>Открыть</code> ещё раз.</p></details><p>Как только вы откроете установщик, вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным &quot;Install&quot;" loading="lazy"></p><p>Чтобы установить Fabric, просто выберите версию игры из раскрывающегося списка и нажмите &#39;Установить&#39;.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖНО</p><p>Убедитесь, что указано &#39;Создать профиль&#39;.</p></div><h2 id="3-you-re-done" tabindex="-1">3. Готово! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Готово!”">​</a></h2><p>Как только установка завершится, вы можете открыть лаунчер Minecraft, выбрать профиль Fabric из списка в левом нижнем углу и нажать Играть!</p><p>Как только установка завершится, вы можете открыть лаунчер Minecraft, выбрать профиль Fabric из списка в левом нижнем углу и нажать Играть!</p><p>Теперь, когда вы установили Fabric, вы можете добавлять моды в свою игру! Смотрите гайд <a href="./finding-mods">Поиск безопасных модов</a> для большей информации.</p><p>Если вы столкнулись с какими-либо проблемами, попросите помощи в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">дискорде Fabric</a> в канале <code>#player-support</code>.</p>`,18)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};